const amqp = require('amqplib');

async function connectToRabbitMQ() {
  try {
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();
    return { connection, channel };
  } catch (err) {
    console.error(err);
    process.exit(1);
  }
}

async function consumeMessages({ connection, channel }) {
  try {
    await channel.assertQueue('my_queue', { durable: true });
    await channel.consume('my_queue', (msg) => {
      if (msg !== null) {
        const message = JSON.parse(msg.content.toString());
        switch (message.type) {
          case 'CREATE_USER':
            createUser(message.payload);
            break;
          case 'UPDATE_USER':
            updateUser(message.payload);
            break;
          default:
            console.log(`Unknown message type: ${message.type}`);
        }
        channel.ack(msg);
      }
    });
  } catch (err) {
    console.error(err);
    process.exit(1);
  }
}

async function createUser(payload) {
  try {
    const db = require('./db'); // assuming a database module
    await db.query(`INSERT INTO users SET ?`, payload);
  } catch (err) {
    console.error(err);
  }
}

async function updateUser(payload) {
  try {
    const db = require('./db');
    await db.query(`UPDATE users SET ? WHERE id = ${payload.id}`, payload);
  } catch (err) {
    console.error(err);
  }
}

connectToRabbitMQ().then(({ connection, channel }) => consumeMessages({ connection, channel }));